What will be the output of the following C code?

```c
#include

int main() {
    int x = 1;

    switch (x) {
        case 1:
            printf("One\n");
        case 2:
            printf("Two\n");
        case 3:
            printf("Three\n");
        default:
            printf("Default\n");
    }

    return 0;
}
```

